// llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp

BoUpSLP::~BoUpSLP() {
  // Delete the instructions that were vectorized.
  for (Instruction *I : VectorizedInstructions) {
    assert(I->use_empty() && "trying to erase instruction with users.");
    I->eraseFromParent();
